args.sparql:
SELECT ?medalLabel WHERE {
  ?athlete wdt:P27 wd:Q79 ;
          wdt:P166 ?medal .
  ?medal rdfs:label ?medalLabel .
  FILTER (LANG(?medalLabel) = 'en')
}

SELECT ?medalLabel
WHERE {
  ?athlete wdt:P31 wd:Q5683901 ;
           wdt:P27 wd:Q79 ;
           wdt:P1346 ?event .

  ?event wdt:P31/wdt:P279* wd:Q259951 .

  ?event p:P1346 ?eventStatement .
  ?eventStatement pq:P245 ?medalType .

  ?medalType rdfs:label ?medalLabel .
  FILTER (LANG(?medalLabel) = 'en')
}

SELECT DISTINCT ?medalTypeLabel
